"use client";

import React, { useState } from "react";
import Calendar, { CalendarType } from "react-calendar";
import { format, isToday } from "date-fns";
import "react-calendar/dist/Calendar.css";
import "./calendar-custom.css";
import TradeModal from "./TradeModal";

type TradeEventType =
  | "warning"
  | "fomc"
  | "amplified"
  | "win"
  | "loss"
  | "pending"
  | "today";

type TradeEvent = {
  date: string;
  label?: string;
  type: TradeEventType;
};

const now = new Date();
const today = now.toISOString().split("T")[0];

const initialTradeEvents: TradeEvent[] = [
  { date: "2025-07-07", type: "pending" },
  { date: "2025-07-08", type: "warning" },
  { date: "2025-07-09", type: "fomc" },
  { date: "2025-07-10", type: "amplified", label: "SPY x 2" },
  { date: "2025-07-15", type: "loss", label: "SPY x 1" },
  { date: today, type: "today" },
  { date: "2025-07-24", type: "pending", label: "SPY x 1" },
  { date: "2025-07-30", type: "fomc" },
  { date: "2025-07-31", type: "win" },
];

const getColor = (type: TradeEventType) => {
  switch (type) {
    case "today":
      return "bg-blue-500";
    case "warning":
      return "bg-orange-500";
    case "fomc":
      return "bg-red-500";
    case "amplified":
      return "bg-green-400";
    case "win":
      return "bg-green-500";
    case "loss":
      return "bg-red-600";
    case "pending":
      return "bg-orange-400";
    default:
      return "";
  }
};

export default function TradeCalendar() {
  const [value, setValue] = useState<Date | null>(new Date());

  const [tradeEvents, setTradeEvents] =
    useState<TradeEvent[]>(initialTradeEvents);

  const [selectedDate, setSelectedDate] = useState<Date | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);

  const handleDateClick = (date: Date) => {
    setSelectedDate(date);
    setIsModalOpen(true);
  };

  const handleSaveTrade = (newTrade: TradeEvent) => {
    setTradeEvents((prev) => [...prev, newTrade]);
  };

  const renderTileContent = ({ date }: { date: Date }) => {
    const dayStr = format(date, "yyyy-MM-dd");
    const match = tradeEvents.find((e) => e.date === dayStr);

    if (match) {
      return (
        <div className="mt-1 text-xs text-white text-center">
          {match.label && <div>{match.label}</div>}
          <div
            className={`w-2 h-2 mx-auto rounded-full ${getColor(match.type)}`}
          />
        </div>
      );
    }

    return null;
  };

  return (
    <div className="bg-[#0F0F17] flex items-center justify-center p-20">
      <Calendar
        onChange={(val) => setValue(val as Date)}
        value={value}
        tileContent={renderTileContent}
        formatShortWeekday={(locale, date) => format(date, "EEE")}
        formatMonthYear={(locale, date) => format(date, "LLLL yyyy")}
        next2Label={null}
        prev2Label={null}
        className="custom-calendar"
      />
    </div>
  );
}
